private struct TikTokTabHost<Content: View>: View {
    let title: String
    let icon: String
    @ViewBuilder var content: () -> Content
    var body: some View { content() }
}

private enum TikTokScreenFactory {
    @ViewBuilder
    static func screen(for tab: String) -> some View {
        switch tab.lowercased() {
        case let t where t.contains("accueil") || t.contains("home") || t.contains("feed") || t.contains("notification"):
            TikTokFeedScreen()
        case let t where t.contains("explor") || t.contains("search") || t.contains("commun"):
            TikTokExploreScreen()
        case let t where t.contains("reel") || t.contains("short") || t.contains("create") || t.contains("post"):
            TikTokReelsScreen()
        case let t where t.contains("profil") || t.contains("profile") || t.contains("network"):
            TikTokProfileScreen()
        default:
            TikTokGenericListScreen(title: tab)
        }
    }
}
